import{_ as r,o as a,c as t,a3 as o}from"./chunks/framework.CjquFG0V.js";const u=JSON.parse('{"title":"86. Travelling Transport And Fares","description":"","frontmatter":{"title":"86. Travelling Transport And Fares","eba":"Medical Scientists, Pharm & Psych 2021-2025","topics":["allowances","travel"]},"headers":[],"relativePath":"ebas/mspp/transport/86-travelling-transport-and-fares.md","filePath":"ebas/mspp/transport/86-travelling-transport-and-fares.md"}'),n={name:"ebas/mspp/transport/86-travelling-transport-and-fares.md"};function s(l,e,i,p,d,c){return a(),t("div",null,[...e[0]||(e[0]=[o('<h1 id="_86-travelling-transport-and-fares" tabindex="-1">86. Travelling Transport And Fares <a class="header-anchor" href="#_86-travelling-transport-and-fares" aria-label="Permalink to &quot;86. Travelling Transport And Fares&quot;">​</a></h1><p><strong>a.</strong> An Employee who is recalled to work outside the normal working hours (provided such work is not continuous with a rostered period of duty) and who uses their vehicle for transport to a place of work shall receive allowances in accordance with this clause.</p><p><strong>b.</strong> Should any Employee be required to use their vehicle during normal working hours on Employer business, the Employee shall receive such allowance based on distance per kilometre travelled as specified by the ATO. The rates will be adjusted each financial year in accordance with the Australian Taxation Office per kilometre rate.</p><p><strong>c.</strong> An Employee on rostered shifts who is required to use public transport to journey to or from work between 9.00 p.m. and 7.00 a.m. shall be provided with transport (taxi or hire car) if no public transport is available for the inward and/or outward journey. The Employer shall be responsible for the payment of such transport.</p><p><strong>d.</strong> Rates will be rounded to the nearest cent.</p><p>Plain language terms: travel, fares, transport allowance.</p>',6)])])}const m=r(n,[["render",s]]);export{u as __pageData,m as default};
